import java.util.Arrays;

public class Solution {

    /**
     * Checks if a number is prime.
     * @param n The number to check.
     * @return true if n is prime, false otherwise.
     */
    private static boolean isPrime(long n) {
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;
        for (long i = 5; i * i <= n; i = i + 6) {
            if (n % i == 0 || n % (i + 2) == 0) return false;
        }
        return true;
    }

    /**
     * Finds the smallest number >= startNum that satisfies the condition (prime or non-prime).
     * @param startNum The starting number.
     * @param mustBePrime True if the target number must be prime, false otherwise.
     * @return The smallest target number.
     */
    private static long findNextTarget(long startNum, boolean mustBePrime) {
        long current = startNum;
        while (true) {
            boolean currentIsPrime = isPrime(current);
            if (mustBePrime) {
                if (currentIsPrime) {
                    return current;
                }
            } else { // Must be non-prime
                if (!currentIsPrime) {
                    return current;
                }
            }
            current++;
        }
    }

    public static long solve(long[] nums) {
        long totalOperations = 0;
        int n = nums.length;

        for (int i = 0; i < n; i++) {
            long currentNum = nums[i];
            boolean mustBePrime = (i % 2 == 0); // Even index must be prime

            long target;
            if (mustBePrime) {
                // Target must be prime
                target = findNextTarget(currentNum, true);
            } else {
                // Target must be non-prime
                target = findNextTarget(currentNum, false);
            }

            // The problem states we can only *increase* the element.
            // The target found by findNextTarget is guaranteed to be >= currentNum.
            totalOperations += (target - currentNum);
        }

        return totalOperations;
    }
}
