import java.util.Arrays;

public class Solution {

    /**
     * Checks if a number is prime.
     * A prime number is a natural number greater than 1 that has no positive divisors other than 1 and itself.
     * @param n The number to check.
     * @return true if n is prime, false otherwise.
     */
    private static boolean isPrime(long n) {
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;
        for (long i = 5; i * i <= n; i = i + 6) {
            if (n % i == 0 || n % (i + 2) == 0) return false;
        }
        return true;
    }

    /**
     * Finds the minimum non-negative increment to make 'n' satisfy the required property.
     * @param n The current number.
     * @param requiredIsPrime True if the target must be prime, false if it must be composite (non-prime).
     * @return The minimum increments needed.
     */
    private static long minIncrements(long n, boolean requiredIsPrime) {
        long current = n;
        while (true) {
            if (requiredIsPrime) {
                if (isPrime(current)) {
                    return current - n;
                }
            } else { // Required to be non-prime (composite or 1)
                if (!isPrime(current)) {
                    // Since input nums[i] >= 1, and we only increase, 
                    // if current is not prime, it satisfies the condition.
                    return current - n;
                }
            }
            current++;
        }
    }

    public static long solve(long[] nums) {
        long totalOperations = 0;
        int n = nums.length;

        for (int i = 0; i < n; i++) {
            long num = nums[i];

            // Even index (i % 2 == 0): Must be prime
            if (i % 2 == 0) {
                // Required: Prime
                long increments = minIncrements(num, true);
                totalOperations += increments;
            } 
            // Odd index (i % 2 == 1): Must be non-prime (not prime)
            else {
                // Required: Non-prime
                long increments = minIncrements(num, false);
                totalOperations += increments;
            }
        }

        return totalOperations;
    }
}
